# TODO: write one equivalent DataFrame query
# +==========+==========+==========+==========+==========+==========+
# Which city has the highest total revenue?
orders_df.groupBy("city").agg(
    sum("revenue").alias("total_revenue")
).orderBy("total_revenue", ascending=False).show()
# Output shows (same as SQL):
'''
+------------+-------------+
|        city|total_revenue|
+------------+-------------+
|      Athens|       1381.0|
|   Heraklion|        685.0|
|      Patras|        370.0|
|Thessaloniki|        315.0|
+------------+-------------+
'''

# Which category has the most orders?
orders_df.groupBy("category").agg(
    count("*").alias("order_count")
).orderBy("order_count", ascending=False).show()
# Output shows (same as SQL):
'''
+-----------+-----------+
|   category|order_count|
+-----------+-----------+
|Electronics|          4|
|     Office|          3|
|  Furniture|          3|
+-----------+-----------+
'''

# Which products have revenue greater than 100?
orders_df.groupBy("product").agg(
    sum("revenue").alias("total_revenue")
).where("total_revenue > 100").orderBy("total_revenue", ascending=False).show()
# Output shows (same as SQL):
'''
+-------+-------------+
|product|total_revenue|
+-------+-------------+
| Laptop|       1200.0|
|Monitor|        620.0|
|  Chair|        340.0|
|   Desk|        240.0|
+-------+-------------+
'''

# What is the average unit price per category?
orders_df.groupBy("category").agg(
    avg("unit_price").alias("average_unit_price")
).show()
# Output shows (same as SQL):
'''
+-----------+------------------+
|   category|average_unit_price|
+-----------+------------------+
|     Office|              4.25|
|Electronics|             402.5|
|  Furniture|             119.0|
+-----------+------------------+
'''

